import { useState } from "react"
import "./index.css"

function Counter() {
  const [count, setCount] = useState(0)

  return (
    <div className="container flex flex-col items-center justify-center min-h-screen py-12">
      <h1 className="text-5xl font-extrabold text-white mb-8 tracking-tighter">Counter</h1>

      {/* Counter Display */}
      <div className="w-full max-w-md p-8 bg-1 shadow-2xl rounded-3xl border border-transparent transition-all duration-300 hover:border-accent hover:shadow-glow">
        <p className="text-lg text-muted mb-2">Current Count</p>
        <div className={`w-full h-6 flex items-center justify-center ${count > 0 ? 'bg-gradient-to-r from-transparent via-accent/10 to-transparent' : 'bg-1'}`}>
          <span className="text-6xl font-black transition-all duration-300 ease-out transform scale-[${Math.max(0.5, Math.min(count / 10 + 1, 2))}]">{count}</span>
        </div>
      </div>

      {/* Button Group */}
      <div className="flex gap-4 mt-12">
        <button 
          onClick={() => setCount(c => Math.max(0, c - 1))}
          className={`px-8 py-4 rounded-full transition-all duration-300 ${count === 0 ? 'opacity-50 cursor-not-allowed' : 'bg-2 hover:bg-1 active:scale-[0.98] shadow-lg focus:ring-2 focus:ring-accent/50'} focus:outline-none`}
          disabled={count === 0}
        >
          &minus;
        </button>

        <button 
          onClick={() => setCount(c => c + 1)}
          className={`px-10 py-4 rounded-full transition-all duration-300 ${count > 0 ? 'bg-gradient-to-r from-transparent via-accent/10 to-transparent hover:from-transparent hover:to-transparent active:scale-[0.98] shadow-xl focus:ring-2 focus:ring-accent/50' : ''} focus:outline-none`}
          disabled={count >= 100}
        >
          &plus;
        </button>
      </div>

      {/* Info Box */}
      <div className="mt-16 w-full max-w-lg bg-1 p-8 rounded-2xl border border-transparent transition-all duration-500 hover:border-accent/20">
        <h2 className="text-3xl font-bold text-white mb-4 tracking-tighter">Advanced Controls</h2>
        <div className="grid grid-cols-2 gap-6 gap-y-4">
          <div>
            <label htmlFor="initial" className="block text-sm text-muted mb-1">Initial Value (0-99)</label>
            <input 
              id="initial" 
              type="number" 
              min={0} 
              max={99} 
              value={count === 0 ? '' : String(count)} 
              onChange={(e) => setCount(parseInt(e.target.value) || 0)} 
              className="w-full bg-0/1 focus:ring-2 focus:ring-accent/30 border-none appearance-none outline-none text-white placeholder:text-dim" 
              placeholder="Enter number (default: 0)" 
              autoFocus
            />
          </div>

          <div>
            <label htmlFor="increment" className="block text-sm text-muted mb-1">Increment Amount</label>
            <input 
              id="increment" 
              type="number" 
              min={1} 
              max={999} 
              value={increment} 
              onChange={(e) => setIncrement(parseInt(e.target.value) || 1)} 
              className="w-full bg-0/1 focus:ring-2 focus:ring-accent/30 border-none appearance-none outline-none placeholder:text-dim" 
              placeholder="Enter amount (default: 1)" 
              autoFocus
            />
          </div>
        </div>

        <div className="flex justify-between items-center mt-8 gap-4">
          <button 
            onClick={() => setCount(c => Math.max(0, c - decrement))}
            className={`px-6 py-3 rounded-full transition-all duration-300 ${count === 0 ? 'opacity-50 cursor-not-allowed' : 'bg-1 hover:bg-2 active:scale-[0.98] shadow-lg focus:ring-2 focus:ring-accent/30'} focus:outline-none`}
            disabled={count === 0}
          >
            &minus; ({decrement})
          </button>

          <button 
            onClick={() => setCount(c => Math.min(c + increment, 999))}
            className={`px-8 py-3 rounded-full transition-all duration-300 ${count >= 100 ? 'opacity-50 cursor-not-allowed' : 'bg-2 hover:bg-1 active:scale-[0.98] shadow-xl focus:ring-2 focus:ring-accent/30'} focus:outline-none`}
            disabled={count >= 100}
          >
            &plus; ({increment})
          </button>
        </div>

        <div className="mt-6 flex justify-between items-center">
          <p className="text-sm text-muted">Current Value: <span className="text-accent font-bold">{count}</span></p>
          <button 
            onClick={() => { setCount(0); setIncrement(1); }}
            className={`px-4 py-2 rounded-lg transition-all duration-300 hover:bg-1 active:scale-[0.98] focus:ring-2 focus:ring-accent/30`}
          >
            Reset
          </button>
        </div>
      </div>
    </div>
  )
}

export default Counter
